```solidity
pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MembershipContract is Ownable, ReentrancyGuard {
    enum State { AirdropEligibility, AirdropClaiming, TokenPurchasing }

    struct User {
        bool claimedAirdrop;
        uint256 tier;
        uint256 purchasedTokens;
    }

    IERC20 public usdcToken;
    IERC20 public gcrToken;
    uint256 public usdcToGcrRate;
    uint256 public airdropAmount;
    uint256[] public tierThresholds;

    mapping(address => User) public users;
    State public currentState = State.AirdropEligibility;

    event ClaimAirdrop(address indexed user, uint256 amount);
    event Purchase(address indexed user, uint256 usdcAmount, uint256 gcrAmount);
    event StateTransition(State oldState, State newState);
    event WithdrawAll(address indexed owner, uint256 amount);

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state");
        _;
    }

    constructor(
        address _usdcToken,
        address _gcrToken,
        uint256 _usdcToGcrRate,
        uint256 _airdropAmount,
        uint256[] memory _tierThresholds
    ) {
        usdcToken = IERC20(_usdcToken);
        gcrToken = IERC20(_gcrToken);
        usdcToGcrRate = _usdcToGcrRate;
        airdropAmount = _airdropAmount;
        tierThresholds = _tierThresholds;
    }

    function claimAirdrop() external onlyInState(State.AirdropClaiming) {
        require(!users[msg.sender].claimedAirdrop, "Already claimed airdrop");

        uint256 amount = airdropAmount;
        users[msg.sender].claimedAirdrop = true;
        users[msg.sender].tier = getTier(msg.sender);

        require(gcrToken.transferFrom(owner(), msg.sender, amount), "Transfer failed");

        emit ClaimAirdrop(msg.sender, amount);
    }

    function purchaseTokens(uint256 usdcAmount) external onlyInState(State.TokenPurchasing) nonReentrant {
        require(usdcAmount > 0, "Invalid amount");

        uint256 gcrAmount = (usdcAmount * usdcToGcrRate) / 1e18;
        uint256 availableAmount = gcrAmount - users[msg.sender].purchasedTokens;

        require(usdcToken.transferFrom(msg.sender, owner(), usdcAmount), "Transfer failed");
        require(gcrToken.transferFrom(owner(), msg.sender, availableAmount), "Transfer failed");

        users[msg.sender].purchasedTokens += availableAmount;

        emit Purchase(msg.sender, usdcAmount, availableAmount);
    }

    function getTier(address user) public view returns (uint256) {
        uint256 balance = usdcToken.balanceOf(user);
        for (uint256 i = 0; i < tierThresholds.length; i++) {
            if (balance >= tierThresholds[i]) {
                return i + 1;
            }
        }
        return 0;
    }

    function setState(State _newState) external onlyOwner {
        require(_newState != currentState, "New state must be different");
        emit StateTransition(currentState, _newState);
        currentState = _newState;
    }

    function withdrawAll() external onlyOwner {
        uint256 balance = gcrToken.balanceOf(address(this));
        require(gcrToken.transfer(owner(), balance), "Withdrawal failed");

        emit WithdrawAll(msg.sender, balance);
    }
}
```

